import "@typespec/http";
import "@typespec/openapi3";
using TypeSpec.Http;
using TypeSpec.OpenAPI;

namespace OpenMeter;

@route("/api/v1/widgets")
@tag("Widgets")
@friendlyName("Widgets")
interface WidgetsEndpoints {
  @get
  @operationId("listWidgets")
  @summary("List widgets")
  list(
    ...QueryCursorPagination,
    @query @encode("application/json") filter?: { name?: FilterString },
  ): CursorPaginatedResponse<Widget> | CommonErrors;
}

@friendlyName("Widget")
model Widget {
  ...Resource;
  @visibility(Lifecycle.Read, Lifecycle.Create)
  slug: Key;
}
